from enum import Enum
from dataclasses import dataclass
import re

class RefusalType(Enum):
    POLICY = "policy"       # provider content filter
    CAPABILITY = "capability"  # "I can't do that"
    AMBIGUITY = "ambiguity"    # "Could you clarify?"
    PARTIAL = "partial"     # completed part but skipped another
    NONE = "none"           # not a refusal


# Phrases that typically indicate a model-generated refusal
REFUSAL_PATTERNS = [
    r"(?i)i('m| am) (not able|unable) to",
    r"(?i)i (can't|cannot) (help|assist|provide|generate|create)",
    r"(?i)i('m| am) sorry,? (but )?(i|that)",
    r"(?i)i('m| am) just an? (ai|language model)",
    r"(?i)this (request |query )?(goes|falls) (beyond|outside)",
    r"(?i)i don't have (access|the ability|permission)",
]

AMBIGUITY_PATTERNS = [
    r"(?i)could you (clarify|elaborate|specify|provide more)",
    r"(?i)i('m| am) not (sure|certain) (what|which|how) you",
    r"(?i)what (do you mean|exactly are you looking for)",
]


@dataclass
class RefusalResult:
    is_refusal: bool
    refusal_type: RefusalType
    text: str


def classify_refusal(resp) -> RefusalResult:
    choice = resp.choices[0]
    text = choice.message.content or ""
    finish_reason = choice.finish_reason

    # Provider-side filter — most reliable signal
    if finish_reason == "content_filter":
        return RefusalResult(is_refusal=True, refusal_type=RefusalType.POLICY, text=text)

    # Very short output on a non-trivial request is suspicious
    if len(text.strip()) < 30 and finish_reason == "stop":
        if any(re.search(p, text) for p in REFUSAL_PATTERNS):
            return RefusalResult(is_refusal=True, refusal_type=RefusalType.CAPABILITY, text=text)

    # Ambiguity check first (model asking for clarification)
    if any(re.search(p, text) for p in AMBIGUITY_PATTERNS):
        return RefusalResult(is_refusal=True, refusal_type=RefusalType.AMBIGUITY, text=text)

    # Model-generated refusal phrases
    if any(re.search(p, text) for p in REFUSAL_PATTERNS):
        # Check if text also contains some content (partial refusal)
        meaningful_length = len(text) > 200
        rtype = RefusalType.PARTIAL if meaningful_length else RefusalType.POLICY
        return RefusalResult(is_refusal=True, refusal_type=rtype, text=text)

    return RefusalResult(is_refusal=False, refusal_type=RefusalType.NONE, text=text)

from dataclasses import dataclass

@dataclass
class UserFacingRefusal:
    message: str
    suggestion: str | None
    retry_button_label: str | None


REFUSAL_MESSAGES: dict[RefusalType, UserFacingRefusal] = {
    RefusalType.POLICY: UserFacingRefusal(
        message="That's outside what I can help with in this context.",
        suggestion="Try rephrasing, or contact support for assistance.",
        retry_button_label="Rephrase and retry",
    ),
    RefusalType.CAPABILITY: UserFacingRefusal(
        message="I don't have access to that information.",
        suggestion="I can help with: [list your supported topics here].",
        retry_button_label=None,
    ),
    RefusalType.AMBIGUITY: UserFacingRefusal(
        message="I want to give you a precise answer — could you tell me a bit more?",
        suggestion=None,
        retry_button_label="Continue",
    ),
    RefusalType.PARTIAL: UserFacingRefusal(
        message="I was able to help with part of your request.",
        suggestion="For the remaining part, [alternative resource or action].",
        retry_button_label=None,
    ),
}


def refusal_to_ui(result: RefusalResult) -> UserFacingRefusal:
    return REFUSAL_MESSAGES.get(
        result.refusal_type,
        UserFacingRefusal(
            message="Something went wrong. Please try again.",
            suggestion=None,
            retry_button_label="Retry",
        ),
    )

from collections import defaultdict
import time

class RefusalMonitor:
    def __init__(self, window_seconds: int = 300):
        self.window = window_seconds
        self._events: list[tuple[float, RefusalType | None]] = []

    def record(self, refusal_type: RefusalType | None) -> None:
        self._events.append((time.monotonic(), refusal_type))
        self._prune()

    def _prune(self) -> None:
        cutoff = time.monotonic() - self.window
        self._events = [(t, r) for t, r in self._events if t >= cutoff]

    def refusal_rate(self) -> float:
        self._prune()
        if not self._events:
            return 0.0
        refused = sum(1 for _, r in self._events if r is not None)
        return refused / len(self._events)

    def breakdown(self) -> dict[str, int]:
        self._prune()
        counts: dict[str, int] = defaultdict(int)
        for _, r in self._events:
            key = r.value if r else "none"
            counts[key] += 1
        return dict(counts)

    def alert_if_high(self, threshold: float = 0.05) -> None:
        rate = self.refusal_rate()
        if rate > threshold:
            print(
                f"[refusal_alert] Rate {rate:.1%} exceeds {threshold:.1%}. "
                f"Breakdown: {self.breakdown()}"
            )


monitor = RefusalMonitor(window_seconds=300)

async def monitored_call(system: str, user_message: str) -> str:
    resp = await client.chat.completions.create(
        model="gpt-4o",
        messages=[
            {"role": "system", "content": system},
            {"role": "user", "content": user_message},
        ],
        max_tokens=512,
    )
    result = classify_refusal(resp)
    monitor.record(result.refusal_type if result.is_refusal else None)
    monitor.alert_if_high(threshold=0.05)
    return result.text
